import { NextRequest, NextResponse } from 'next/server';
import { writeFileSync, readFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';

// Types for local content management
export interface LocalPost {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string;
  status: 'draft' | 'publish' | 'private' | 'trash';
  author: string;
  createdAt: string;
  updatedAt: string;
  categories: string[];
  tags: string[];
  featuredImage?: string;
  meta?: {
    description?: string;
    keywords?: string[];
  };
}

export interface LocalPage {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string;
  status: 'draft' | 'publish' | 'private' | 'trash';
  author: string;
  createdAt: string;
  updatedAt: string;
  template?: string;
  meta?: {
    description?: string;
    keywords?: string[];
  };
}

export interface LocalCategory {
  id: string;
  name: string;
  slug: string;
  description: string;
  parent?: string;
  createdAt: string;
  updatedAt: string;
}

export interface LocalMedia {
  id: string;
  filename: string;
  originalName: string;
  mimeType: string;
  size: number;
  url: string;
  altText?: string;
  caption?: string;
  uploadedAt: string;
}

// Data storage paths
const DATA_DIR = join(process.cwd(), 'data');
const POSTS_FILE = join(DATA_DIR, 'posts.json');
const PAGES_FILE = join(DATA_DIR, 'pages.json');
const CATEGORIES_FILE = join(DATA_DIR, 'categories.json');
const MEDIA_FILE = join(DATA_DIR, 'media.json');

// Ensure data directory exists
function ensureDataDir() {
  if (!existsSync(DATA_DIR)) {
    mkdirSync(DATA_DIR, { recursive: true });
  }
}

// Generic file operations
function readData<T>(filePath: string, defaultValue: T[]): T[] {
  ensureDataDir();
  try {
    if (existsSync(filePath)) {
      const data = readFileSync(filePath, 'utf-8');
      return JSON.parse(data);
    }
  } catch (error) {
    console.error(`Error reading ${filePath}:`, error);
  }
  return defaultValue;
}

function writeData<T>(filePath: string, data: T[]): void {
  ensureDataDir();
  try {
    writeFileSync(filePath, JSON.stringify(data, null, 2));
  } catch (error) {
    console.error(`Error writing ${filePath}:`, error);
    throw error;
  }
}

// API handlers
export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const type = searchParams.get('type');
  const id = searchParams.get('id');
  const slug = searchParams.get('slug');

  try {
    switch (type) {
      case 'posts':
        if (id) {
          const posts = readData<LocalPost>(POSTS_FILE, []);
          const post = posts.find(p => p.id === id);
          return NextResponse.json(post || null);
        } else if (slug) {
          const posts = readData<LocalPost>(POSTS_FILE, []);
          const post = posts.find(p => p.slug === slug);
          return NextResponse.json(post || null);
        } else {
          const posts = readData<LocalPost>(POSTS_FILE, []);
          return NextResponse.json(posts);
        }
      
      case 'pages':
        if (id) {
          const pages = readData<LocalPage>(PAGES_FILE, []);
          const page = pages.find(p => p.id === id);
          return NextResponse.json(page || null);
        } else if (slug) {
          const pages = readData<LocalPage>(PAGES_FILE, []);
          const page = pages.find(p => p.slug === slug);
          return NextResponse.json(page || null);
        } else {
          const pages = readData<LocalPage>(PAGES_FILE, []);
          return NextResponse.json(pages);
        }
      
      case 'categories':
        if (id) {
          const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
          const category = categories.find(c => c.id === id);
          return NextResponse.json(category || null);
        } else if (slug) {
          const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
          const category = categories.find(c => c.slug === slug);
          return NextResponse.json(category || null);
        } else {
          const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
          return NextResponse.json(categories);
        }
      
      case 'media':
        if (id) {
          const media = readData<LocalMedia>(MEDIA_FILE, []);
          const item = media.find(m => m.id === id);
          return NextResponse.json(item || null);
        } else {
          const media = readData<LocalMedia>(MEDIA_FILE, []);
          return NextResponse.json(media);
        }
      
      case 'analytics':
        const posts = readData<LocalPost>(POSTS_FILE, []);
        const pages = readData<LocalPage>(PAGES_FILE, []);
        const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
        const media = readData<LocalMedia>(MEDIA_FILE, []);

        return NextResponse.json({
          totalPosts: posts.length,
          publishedPosts: posts.filter(post => post.status === 'publish').length,
          draftPosts: posts.filter(post => post.status === 'draft').length,
          totalPages: pages.length,
          publishedPages: pages.filter(page => page.status === 'publish').length,
          totalCategories: categories.length,
          totalMedia: media.length,
          posts,
          pages,
          categories,
          media,
        });
      
      default:
        return NextResponse.json({ error: 'Invalid type parameter' }, { status: 400 });
    }
  } catch (error) {
    console.error('API GET error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { type, data } = body;

    switch (type) {
      case 'posts':
        const posts = readData<LocalPost>(POSTS_FILE, []);
        const newPost: LocalPost = {
          ...data,
          id: Date.now().toString(),
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        };
        posts.push(newPost);
        writeData(POSTS_FILE, posts);
        return NextResponse.json(newPost);
      
      case 'pages':
        const pages = readData<LocalPage>(PAGES_FILE, []);
        const newPage: LocalPage = {
          ...data,
          id: Date.now().toString(),
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        };
        pages.push(newPage);
        writeData(PAGES_FILE, pages);
        return NextResponse.json(newPage);
      
      case 'categories':
        const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
        const newCategory: LocalCategory = {
          ...data,
          id: Date.now().toString(),
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        };
        categories.push(newCategory);
        writeData(CATEGORIES_FILE, categories);
        return NextResponse.json(newCategory);
      
      case 'media':
        const media = readData<LocalMedia>(MEDIA_FILE, []);
        const newMedia: LocalMedia = {
          ...data,
          id: Date.now().toString(),
          uploadedAt: new Date().toISOString(),
        };
        media.push(newMedia);
        writeData(MEDIA_FILE, media);
        return NextResponse.json(newMedia);
      
      default:
        return NextResponse.json({ error: 'Invalid type parameter' }, { status: 400 });
    }
  } catch (error) {
    console.error('API POST error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PUT(request: NextRequest) {
  try {
    const body = await request.json();
    const { type, id, data } = body;

    switch (type) {
      case 'posts':
        const posts = readData<LocalPost>(POSTS_FILE, []);
        const postIndex = posts.findIndex(p => p.id === id);
        if (postIndex === -1) {
          return NextResponse.json({ error: 'Post not found' }, { status: 404 });
        }
        posts[postIndex] = {
          ...posts[postIndex],
          ...data,
          updatedAt: new Date().toISOString(),
        };
        writeData(POSTS_FILE, posts);
        return NextResponse.json(posts[postIndex]);
      
      case 'pages':
        const pages = readData<LocalPage>(PAGES_FILE, []);
        const pageIndex = pages.findIndex(p => p.id === id);
        if (pageIndex === -1) {
          return NextResponse.json({ error: 'Page not found' }, { status: 404 });
        }
        pages[pageIndex] = {
          ...pages[pageIndex],
          ...data,
          updatedAt: new Date().toISOString(),
        };
        writeData(PAGES_FILE, pages);
        return NextResponse.json(pages[pageIndex]);
      
      case 'categories':
        const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
        const categoryIndex = categories.findIndex(c => c.id === id);
        if (categoryIndex === -1) {
          return NextResponse.json({ error: 'Category not found' }, { status: 404 });
        }
        categories[categoryIndex] = {
          ...categories[categoryIndex],
          ...data,
          updatedAt: new Date().toISOString(),
        };
        writeData(CATEGORIES_FILE, categories);
        return NextResponse.json(categories[categoryIndex]);
      
      default:
        return NextResponse.json({ error: 'Invalid type parameter' }, { status: 400 });
    }
  } catch (error) {
    console.error('API PUT error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const type = searchParams.get('type');
    const id = searchParams.get('id');

    if (!type || !id) {
      return NextResponse.json({ error: 'Type and ID parameters required' }, { status: 400 });
    }

    switch (type) {
      case 'posts':
        const posts = readData<LocalPost>(POSTS_FILE, []);
        const filteredPosts = posts.filter(p => p.id !== id);
        if (filteredPosts.length === posts.length) {
          return NextResponse.json({ error: 'Post not found' }, { status: 404 });
        }
        writeData(POSTS_FILE, filteredPosts);
        return NextResponse.json({ success: true });
      
      case 'pages':
        const pages = readData<LocalPage>(PAGES_FILE, []);
        const filteredPages = pages.filter(p => p.id !== id);
        if (filteredPages.length === pages.length) {
          return NextResponse.json({ error: 'Page not found' }, { status: 404 });
        }
        writeData(PAGES_FILE, filteredPages);
        return NextResponse.json({ success: true });
      
      case 'categories':
        const categories = readData<LocalCategory>(CATEGORIES_FILE, []);
        const filteredCategories = categories.filter(c => c.id !== id);
        if (filteredCategories.length === categories.length) {
          return NextResponse.json({ error: 'Category not found' }, { status: 404 });
        }
        writeData(CATEGORIES_FILE, filteredCategories);
        return NextResponse.json({ success: true });
      
      case 'media':
        const media = readData<LocalMedia>(MEDIA_FILE, []);
        const filteredMedia = media.filter(m => m.id !== id);
        if (filteredMedia.length === media.length) {
          return NextResponse.json({ error: 'Media not found' }, { status: 404 });
        }
        writeData(MEDIA_FILE, filteredMedia);
        return NextResponse.json({ success: true });
      
      default:
        return NextResponse.json({ error: 'Invalid type parameter' }, { status: 400 });
    }
  } catch (error) {
    console.error('API DELETE error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
